// Recomienda la ubicación de altura MÁS LLENA (mayor stock total sumando sus
// cajas). Así una sola bajada cubre la necesidad y los SKUs tienden a
// agruparse en las posiciones grandes → menos viajes.
function mejorAltCubre(altByUbi) {
  const entries = Object.entries(altByUbi || {});
  if (!entries.length) return null;
  return entries.sort((a, b) => b[1] - a[1])[0][0];
}
// Fuente única de los "viajes" (bajar de altura) para la pantalla y el Excel.
// Devuelve los SKUs que faltan en piso pero tienen altura, filtrados por Calle,
// igual que el Plan de Viajes. Cada item: {ref, desc, uniReq, comp, stockPiso, mejorAlt, ...}
function listaViajes(data, sorted, planCalle, planFam) {
  const reabasto = (data?.pedidosActivos || []).filter(p => !p.esMasivo && !p.programadoFuturo && !reqExcluida(p.tipoDocto, p.notaTxt) && (p.clasificacion === "reabasto" || p.clasificacion === "parcial" || p.clasificacion === "ruptura"));
  const skuMaestro = Object.fromEntries(sorted.map(x => [x.id, x]));
  const skuFalta = {};
  reabasto.forEach(p => {
    (p.refs || []).forEach(r => {
      if (!r.hasPiso && r.hasAlt) {
        if (!skuFalta[r.ref]) {
          const _m = skuMaestro[r.ref] || {};
          skuFalta[r.ref] = {
            ref: r.ref,
            desc: r.desc,
            uniReq: 0,
            pedidos: new Set(),
            stockAlt: 0,
            stockPiso: _m.stock_piso || 0,
            comp: _m.comp || 0,
            posPiso: [],
            altByUbi: null,
            mejorAlt: null
          };
        }
        skuFalta[r.ref].uniReq += r.cant;
        skuFalta[r.ref].pedidos.add(p.id);
        const pos = (data?.invBySKU || {})[r.ref] || [];
        skuFalta[r.ref].stockAlt = pos.filter(x => x.nivel >= 2).reduce((t, x) => t + x.saldo, 0);
        if (!skuFalta[r.ref].posPiso.length) {
          skuFalta[r.ref].posPiso = pos.filter(x => x.nivel <= 1 && x.saldo > 0).sort((a, b) => b.saldo - a.saldo).slice(0, 3).map(x => x.ubi);
        }
        if (!skuFalta[r.ref].altByUbi) {
          // Stock de altura agrupado por ubicación (suma de sus cajas). La
          // posición recomendada se decide DESPUÉS con las unidades requeridas.
          const _byUbi = {};
          pos.filter(x => x.nivel >= 2 && x.saldo > 0).forEach(x => {
            _byUbi[x.ubi] = (_byUbi[x.ubi] || 0) + x.saldo;
          });
          skuFalta[r.ref].altByUbi = _byUbi;
        }
      }
    });
  });
  let listaV = Object.values(skuFalta).map(s => ({
    ...s,
    nPedidos: s.pedidos.size,
    pallets: Math.ceil(s.uniReq / 72),
    // Mejor altura = la posición más llena (mayor stock total) → menos viajes
    mejorAlt: mejorAltCubre(s.altByUbi)
  })).sort((a, b) => b.uniReq - a.uniReq);
  if (planCalle !== "todas") {
    listaV = listaV.filter(s => {
      const f = familia(s.desc) || "";
      const d = (s.desc || "").toUpperCase();
      if (planCalle === "C1") return (f === "3110" && !es3110S(d)) || ["102", "405"].includes(f);
      if (planCalle === "C2") return f === "501" && esCalle2(d) || f === "503" || es3110S(d) || f === "101";
      if (planCalle === "C3") return f === "501" && !esCalle2(d);
      if (planCalle === "C4") return ["3120", "3130", "3300"].includes(f);
      return true;
    });
  }
  // Filtro por familia (dropdown "Todas familias / Familia XXX")
  if (planFam && planFam !== "todas") {
    listaV = listaV.filter(s => (familia(s.desc) || "") === planFam);
  }
  return listaV;
}
// Export del Excel de Reposición ("viajes" de bajar de altura) con formato fijo:
//  1) Un SKU por fila (solo los que tienen posición de altura) · columnas:
//     SKU, Familia, Comprometido, Piso, Bajar(cajas), Posición
//  2) "Bajar (cajas)" = ceil(unidades requeridas por los pedidos / 9)
//  3) Merge vertical de Posición cuando varios SKUs comparten posición (= mismo viaje) + amarillo
//  4) Orden por Calle (B→E) y luego por texto de posición
//  5) Encabezado azul 1F4E78, cuerpo Arial 10 centrado con bordes grises, borde medio por grupo,
//     autofiltro, panel congelado en fila 1 y anchos fijos.
async function exportarPlanTurno(items, calleSel = "todas") {
  if (!window.ExcelJS) {
    alert("Librería ExcelJS no disponible (no se pudo cargar). Reintenta con conexión.");
    return;
  }
  const ahora = new Date();
  const CALLE_ORD = {
    B: 1,
    C: 2,
    D: 3,
    E: 4
  };

  // 1 · Un SKU por fila, tomado de los mismos "viajes" que muestra la pantalla.
  //     Solo los que tienen posición de altura (los que arman un viaje real).
  let filas = (items || []).filter(s => s.mejorAlt).map(s => {
    // Posición tal cual aparece en el inventario (ej: B3121, C0121, D1532, E3451)
    const posicion = String(s.mejorAlt || "").trim().toUpperCase();
    const calleLetra = posicion[0] || "";
    return {
      sku: String(s.ref),
      familia: familia(s.desc) || "OTROS",
      comprometido: s.comp,
      piso: s.stockPiso,
      cajas: Math.ceil((s.uniReq || 0) / 9),
      posicion,
      calleNum: CALLE_ORD[calleLetra] || 9
    };
  }).filter(Boolean);

  // 4 · Orden: por Calle, luego por texto de posición (numérico)
  filas.sort((a, b) => a.calleNum - b.calleNum || a.posicion.localeCompare(b.posicion, "es", {
    numeric: true
  }));

  // Workbook + hoja (panel congelado en fila 1)
  const calleTag = calleSel && calleSel !== "todas" ? calleSel.toUpperCase() : "";
  const wb = new window.ExcelJS.Workbook();
  const ws = wb.addWorksheet(calleTag ? `Reposición ${calleTag}` : "Reposición", {
    views: [{
      state: "frozen",
      ySplit: 1
    }]
  });
  ws.columns = [{
    header: "SKU",
    key: "sku",
    width: 14
  }, {
    header: "Familia",
    key: "familia",
    width: 12
  }, {
    header: "Comprometido",
    key: "comprometido",
    width: 15
  }, {
    header: "Piso",
    key: "piso",
    width: 10
  }, {
    header: "Bajar (cajas)",
    key: "cajas",
    width: 14
  }, {
    header: "Posición",
    key: "posicion",
    width: 20
  }];

  // Estilos reutilizables
  const thinGray = {
    style: "thin",
    color: {
      argb: "FFBFBFBF"
    }
  };
  const medGray = {
    style: "medium",
    color: {
      argb: "FF808080"
    }
  };
  const bordeFino = {
    top: thinGray,
    bottom: thinGray,
    left: thinGray,
    right: thinGray
  };
  const centro = {
    horizontal: "center",
    vertical: "middle"
  };
  const NCOL = 6; // SKU · Familia · Comprometido · Piso · Bajar(cajas) · Posición (última)

  // 5 · Encabezado azul, texto blanco negrita centrado
  const hRow = ws.getRow(1);
  hRow.height = 20;
  for (let col = 1; col <= NCOL; col++) {
    const c = hRow.getCell(col);
    c.font = {
      name: "Arial",
      size: 10,
      bold: true,
      color: {
        argb: "FFFFFFFF"
      }
    };
    c.fill = {
      type: "pattern",
      pattern: "solid",
      fgColor: {
        argb: "FF1F4E78"
      }
    };
    c.alignment = centro;
    c.border = bordeFino;
  }

  // Filas de datos
  filas.forEach(f => ws.addRow({
    sku: f.sku,
    familia: f.familia,
    comprometido: f.comprometido,
    piso: f.piso,
    cajas: f.cajas,
    posicion: f.posicion
  }));

  // 3 · Grupos contiguos por posición (ya ordenado)
  const grupos = [];
  let gi = 0;
  while (gi < filas.length) {
    let gj = gi;
    while (gj + 1 < filas.length && filas[gj + 1].posicion === filas[gi].posicion) gj++;
    grupos.push({
      start: gi,
      end: gj,
      size: gj - gi + 1
    });
    gi = gj + 1;
  }

  // Cuerpo: Arial 10 centrado con bordes; resaltado amarillo + merge en posiciones compartidas
  grupos.forEach(gr => {
    const compartida = gr.size >= 2;
    for (let r = gr.start; r <= gr.end; r++) {
      const excelRow = r + 2; // fila 1 = encabezado
      for (let col = 1; col <= NCOL; col++) {
        const c = ws.getRow(excelRow).getCell(col);
        c.font = {
          name: "Arial",
          size: 10
        };
        c.alignment = centro;
        c.border = {
          ...bordeFino
        };
        if (compartida) c.fill = {
          type: "pattern",
          pattern: "solid",
          fgColor: {
            argb: "FFFFF2CC"
          }
        };
      }
    }
    // Merge vertical de la celda Posición (col 5) cuando comparten
    if (compartida) {
      ws.mergeCells(gr.start + 2, NCOL, gr.end + 2, NCOL);
      ws.getCell(gr.start + 2, NCOL).alignment = centro;
    }
    // Borde medio gris al final del grupo (separador visual)
    const lastExcel = gr.end + 2;
    for (let col = 1; col <= NCOL; col++) {
      const c = ws.getRow(lastExcel).getCell(col);
      c.border = {
        ...(c.border || bordeFino),
        bottom: medGray
      };
    }
  });

  // Autofiltro en el encabezado
  ws.autoFilter = {
    from: {
      row: 1,
      column: 1
    },
    to: {
      row: 1,
      column: NCOL
    }
  };

  // Descargar
  const buf = await wb.xlsx.writeBuffer();
  const blob = new Blob([buf], {
    type: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
  });
  const a = document.createElement("a");
  a.href = URL.createObjectURL(blob);
  a.download = `reposicion_cedi_${calleTag ? calleTag + "_" : ""}${ahora.toISOString().slice(0, 10)}_${String(ahora.getHours()).padStart(2, "0")}${String(ahora.getMinutes()).padStart(2, "0")}.xlsx`;
  a.click();
  setTimeout(() => URL.revokeObjectURL(a.href), 2000);
}
